use ndarray::Axis;
use crate::common_types::{Matrix, Vector};
use crate::errors::Result;

/// Create a diagonal matrix from a vector
pub fn diag(v: &Vector) -> Matrix {
    let n = v.len();
    let mut mat = Matrix::zeros((n, n));
    for i in 0..n {
        mat[[i, i]] = v[i];
    }
    mat
}

/// Extract the diagonal of a matrix as a vector
pub fn diag_vec(m: &Matrix) -> Vector {
    let n = m.nrows().min(m.ncols());
    let mut v = Vector::zeros(n);
    for i in 0..n {
        v[i] = m[[i, i]];
    }
    v
}

/// Compute the Frobenius norm of a matrix
pub fn frobenius_norm(m: &Matrix) -> f64 {
    m.iter().map(|x| x * x).sum::<f64>().sqrt()
}

/// Compute the trace of a square matrix
pub fn trace(m: &Matrix) -> Result<f64> {
    use crate::validation::validate_square_matrix;
    validate_square_matrix(m.dim())?;
    Ok((0..m.nrows()).map(|i| m[[i, i]]).sum())
}

/// Create an identity matrix of size n×n
pub fn eye(n: usize) -> Matrix {
    let mut m = Matrix::zeros((n, n));
    for i in 0..n {
        m[[i, i]] = 1.0;
    }
    m
}

/// Compute column-wise mean of a matrix
pub fn col_mean(m: &Matrix) -> Vector {
    m.mean_axis(Axis(0)).unwrap()
}

/// Compute row-wise mean of a matrix
pub fn row_mean(m: &Matrix) -> Vector {
    m.mean_axis(Axis(1)).unwrap()
}

/// Center a matrix by subtracting column means
pub fn center_columns(m: &Matrix) -> (Matrix, Vector) {
    let means = col_mean(m);
    let centered = m - &means;
    (centered, means)
}

/// Scale columns to unit variance
pub fn scale_columns(m: &Matrix) -> (Matrix, Vector) {
    let n = m.nrows() as f64;
    let means = col_mean(m);
    let centered = m - &means;

    // Compute standard deviations
    let mut stds = Vector::zeros(m.ncols());
    for (j, col) in centered.axis_iter(Axis(1)).enumerate() {
        let variance = col.iter().map(|x| x * x).sum::<f64>() / (n - 1.0);
        stds[j] = variance.sqrt();
        // Avoid division by zero
        if stds[j] < 1e-10 {
            stds[j] = 1.0;
        }
    }

    // Scale the centered matrix
    let mut scaled = centered.clone();
    for (j, mut col) in scaled.axis_iter_mut(Axis(1)).enumerate() {
        col /= stds[j];
    }

    (scaled, stds)
}

/// Standardize a matrix (center and scale)
pub fn standardize(m: &Matrix) -> (Matrix, Vector, Vector) {
    let (centered, means) = center_columns(m);
    let (scaled, stds) = scale_columns(&centered);
    (scaled, means, stds)
}

/// Check if two floating point numbers are approximately equal
pub fn approx_equal(a: f64, b: f64, tol: f64) -> bool {
    (a - b).abs() < tol
}

/// Check if two matrices are approximately equal
pub fn approx_equal_matrix(a: &Matrix, b: &Matrix, tol: f64) -> bool {
    a.shape() == b.shape() && 
    a.iter().zip(b.iter()).all(|(x, y)| approx_equal(*x, *y, tol))
}

/// Compute the rank of a matrix based on singular values
pub fn matrix_rank(singular_values: &Vector, tol: Option<f64>) -> usize {
    let tol = tol.unwrap_or(1e-10);
    singular_values.iter().filter(|&&s| s > tol).count()
}

