use crate::object::RObject;
use std::any::Any;
use std::collections::HashMap;

/// Generic vector type that can hold any R atomic type
#[derive(Debug, Clone, PartialEq)]
pub struct Vector<T> {
    pub values: Vec<T>,
}

impl<T: 'static + Clone + std::fmt::Debug> RObject for Vector<T> {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        match std::any::type_name::<T>() {
            name if name.contains("f64") => "numeric",
            name if name.contains("i32") => "integer",
            name if name.contains("bool") => "logical",
            name if name.contains("String") => "character",
            _ => "unknown",
        }
    }

    fn length(&self) -> usize {
        self.values.len()
    }

    fn is_na(&self, _index: usize) -> bool {
        // For non-Option types, values are never NA
        false
    }

    fn print(&self) -> String {
        format!("{:?}", self.values)
    }
}

/// List type that can hold heterogeneous R objects
#[derive(Clone)]
pub struct List {
    pub elements: Vec<Box<dyn RObject>>,
}

impl RObject for List {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        "list"
    }

    fn length(&self) -> usize {
        self.elements.len()
    }

    fn is_na(&self, _index: usize) -> bool {
        false
    }

    fn print(&self) -> String {
        let items: Vec<String> = self.elements.iter()
            .enumerate()
            .map(|(i, e)| format!("[[{}]]\n{}", i + 1, e.print()))
            .collect();
        items.join("\n\n")
    }
}

/// DataFrame type
#[derive(Clone)]
pub struct DataFrame {
    pub columns: HashMap<String, Box<dyn RObject>>,
}

impl RObject for DataFrame {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        "data.frame"
    }

    fn length(&self) -> usize {
        // Return number of rows
        self.columns.values()
            .next()
            .map(|col| col.length())
            .unwrap_or(0)
    }

    fn is_na(&self, _index: usize) -> bool {
        false
    }

    fn print(&self) -> String {
        let mut result = String::new();
        let col_names: Vec<&String> = self.columns.keys().collect();

        // Header
        result.push_str(&col_names.iter().map(|n| n.as_str()).collect::<Vec<_>>().join("\t"));
        result.push('\n');

        // Rows
        let nrows = self.length();
        for i in 0..nrows {
            let row: Vec<String> = col_names.iter()
                .map(|name| {
                    self.columns.get(*name)
                        .map(|col| {
                            // Extract value at index i
                            if let Some(vec_f64) = col.as_any().downcast_ref::<Vector<f64>>() {
                                vec_f64.values.get(i).map(|v| v.to_string()).unwrap_or_default()
                            } else if let Some(vec_i32) = col.as_any().downcast_ref::<Vector<i32>>() {
                                vec_i32.values.get(i).map(|v| v.to_string()).unwrap_or_default()
                            } else if let Some(vec_str) = col.as_any().downcast_ref::<Vector<String>>() {
                                vec_str.values.get(i).cloned().unwrap_or_default()
                            } else if let Some(vec_bool) = col.as_any().downcast_ref::<Vector<bool>>() {
                                vec_bool.values.get(i).map(|v| v.to_string()).unwrap_or_default()
                            } else {
                                String::new()
                            }
                        })
                        .unwrap_or_default()
                })
                .collect();
            result.push_str(&row.join("\t"));
            result.push('\n');
        }

        result
    }
}

/// Matrix type
#[derive(Debug, Clone, PartialEq)]
pub struct Matrix<T> {
    pub values: Vec<T>,
    pub nrow: usize,
    pub ncol: usize,
}

impl<T: 'static + Clone + std::fmt::Debug> RObject for Matrix<T> {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        "matrix"
    }

    fn length(&self) -> usize {
        self.values.len()
    }

    fn is_na(&self, _index: usize) -> bool {
        false
    }

    fn print(&self) -> String {
        let mut result = String::new();
        for i in 0..self.nrow {
            let row: Vec<String> = (0..self.ncol)
                .map(|j| format!("{:?}", self.values[i + j * self.nrow]))
                .collect();
            result.push_str(&row.join("\t"));
            result.push('\n');
        }
        result
    }
}

/// Array type (multidimensional)
#[derive(Debug, Clone)]
pub struct Array<T> {
    pub values: Vec<T>,
    pub dims: Vec<usize>,
}

impl<T: 'static + Clone + std::fmt::Debug> RObject for Array<T> {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        "array"
    }

    fn length(&self) -> usize {
        self.values.len()
    }

    fn is_na(&self, _index: usize) -> bool {
        false
    }

    fn print(&self) -> String {
        format!("{}-dimensional array with dimensions {:?}", self.dims.len(), self.dims)
    }
}

/// Factor type
#[derive(Debug, Clone)]
pub struct Factor {
    pub values: Vec<i32>,  // indices into levels
    pub levels: Vec<String>,
}

impl RObject for Factor {
    fn as_any(&self) -> &dyn Any {
        self
    }

    fn r_type(&self) -> &str {
        "factor"
    }

    fn length(&self) -> usize {
        self.values.len()
    }

    fn is_na(&self, index: usize) -> bool {
        self.values.get(index).map(|&v| v < 0).unwrap_or(true)
    }

    fn print(&self) -> String {
        let labels: Vec<String> = self.values.iter()
            .map(|&idx| {
                if idx < 0 {
                    "NA".to_string()
                } else {
                    self.levels.get(idx as usize)
                        .cloned()
                        .unwrap_or_else(|| "NA".to_string())
                }
            })
            .collect();

        format!("{:?}\nLevels: {:?}", labels, self.levels)
    }
}

// Type aliases for common vector types
pub type NumericVector = Vector<f64>;
pub type IntegerVector = Vector<i32>;
pub type LogicalVector = Vector<bool>;
pub type CharacterVector = Vector<String>;

// Type aliases for vectors with NA support
pub type NumericVectorNA = Vector<Option<f64>>;
pub type IntegerVectorNA = Vector<Option<i32>>;
pub type LogicalVectorNA = Vector<Option<bool>>;
pub type CharacterVectorNA = Vector<Option<String>>;

