use crate::types::*;
use std::cmp::Ordering;

/// Trait for statistical minimum
pub trait Min {
    type Output;
    fn min(&self) -> Option<Self::Output>;
}

/// Trait for statistical maximum
pub trait Max {
    type Output;
    fn max(&self) -> Option<Self::Output>;
}

/// Trait for range (min, max)
pub trait Range {
    type Output;
    fn range(&self) -> Option<(Self::Output, Self::Output)>;
}

/// Trait for mean calculation
pub trait Mean {
    fn mean(&self) -> Option<f64>;
}

/// Trait for median calculation
pub trait Median {
    fn median(&self) -> Option<f64>;
}

/// Trait for variance calculation
pub trait Variance {
    fn var(&self) -> Option<f64>;
    fn var_pop(&self) -> Option<f64>; // Population variance
}

/// Trait for standard deviation
pub trait StdDev {
    fn sd(&self) -> Option<f64>;
    fn sd_pop(&self) -> Option<f64>; // Population standard deviation
}

/// Trait for sum calculation
pub trait Sum {
    type Output;
    fn sum(&self) -> Self::Output;
}

/// Trait for quantile calculation
pub trait Quantile {
    fn quantile(&self, prob: f64) -> Option<f64>;
    fn quartiles(&self) -> Option<(f64, f64, f64)>; // Q1, Q2 (median), Q3
}

/// Trait for covariance between two vectors
pub trait Covariance<T> {
    fn cov(&self, other: &T) -> Option<f64>;
}

/// Trait for correlation between two vectors
pub trait Correlation<T> {
    fn cor(&self, other: &T) -> Option<f64>;
}

/// Helper function to handle NA values in calculations
fn filter_na<T: Clone>(values: &[Option<T>]) -> Vec<T> {
    values.iter()
        .filter_map(|x| x.clone())
        .collect()
}

// Implementation for Vector<f64>
impl Min for Vector<f64> {
    type Output = f64;

    fn min(&self) -> Option<Self::Output> {
        self.values.iter()
            .filter(|&&x| !x.is_nan())
            .min_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal))
            .copied()
    }
}

impl Max for Vector<f64> {
    type Output = f64;

    fn max(&self) -> Option<Self::Output> {
        self.values.iter()
            .filter(|&&x| !x.is_nan())
            .max_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal))
            .copied()
    }
}

impl Range for Vector<f64> {
    type Output = f64;

    fn range(&self) -> Option<(Self::Output, Self::Output)> {
